mapper.update:
update pr_import_unit_valve a
    left join sys_organization b on a.company_id = b.company_id and a.org_name = b.name
set a.org_id = b.id
where a.company_id = #{companyId}
  and a.type = '0'
  and a.create_by = #{create}
  and b.company_id = #{companyId}
  and a.org_name = b.name

mapper.select:
select 
from pr_import_unit_valve
where company_id = #{companyId}
  and type = '0'
  and create_by = #{create}
  and (unit_id is null or unit_id = '')

select t.*
from pr_import_unit_valve t
         inner join (
    select meter_num
    from pr_import_unit_valve
    where company_id = #{companyId}
      and type = '0'
      and create_by = #{create}
    group by meter_num
    having count(1) > 1
) dup on t.meter_num = dup.meter_num
where t.company_id = #{companyId}
  and t.type = '0'
  and t.create_by = #{create}
limit 500

select count(1)
from pr_import_unit_valve
where company_id = #{companyId}
  and create_by = #{create}
  and type = '0'

